import React, { useState } from "react";
import { View, StyleSheet, Pressable, ScrollView, Platform, Dimensions } from "react-native";
import { NativeStackNavigationProp } from "@react-navigation/native-stack";
import { RootStackParamList } from "@/navigation/RootNavigator";
import { ScreenScrollView } from "@/components/ScreenScrollView";
import { ThemedText } from "@/components/ThemedText";
import { useTheme } from "@/hooks/useTheme";
import { useAuth } from "@/hooks/useAuth";
import { useApi } from "@/hooks/useApi";
import { Spacing, BorderRadius, Typography } from "@/constants/theme";
import { Feather } from "@expo/vector-icons";
import Slider from '@react-native-community/slider';
import * as Haptics from 'expo-haptics';

const ACCENT_COLOR = "#10B981";
const { width } = Dimensions.get('window');

type FiltersScreenNavigationProp = NativeStackNavigationProp<RootStackParamList, "Filters">;

interface FiltersScreenProps {
  navigation: FiltersScreenNavigationProp;
}

export default function FiltersScreen({ navigation }: FiltersScreenProps) {
  const { theme } = useTheme();
  const { user, token, updateProfile } = useAuth();
  const api = useApi();

  const [minAge, setMinAge] = useState(user?.preferences?.ageRange?.min || 18);
  const [maxAge, setMaxAge] = useState(user?.preferences?.ageRange?.max || 35);
  const [distance, setDistance] = useState(user?.preferences?.maxDistance || 50);
  const [lookingFor, setLookingFor] = useState<string>(user?.lifestyle?.lookingFor || 'relationship');
  const [religion, setReligion] = useState<string>(user?.lifestyle?.religion || 'any');
  const [saving, setSaving] = useState(false);

  const handleApply = async () => {
    if (!token) return;
    try {
      setSaving(true);
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Heavy);
      // ... your API logic remains the same
      navigation.goBack();
    } catch (error) {
      console.error(error);
    } finally {
      setSaving(false);
    }
  };

  return (
    <View style={[styles.container, { backgroundColor: theme.background }]}>
      {/* HEADER */}
      <View style={styles.header}>
        <Pressable style={styles.backCircle} onPress={() => navigation.goBack()}>
          <Feather name="x" size={24} color={theme.text} />
        </Pressable>
        <ThemedText style={styles.headerTitle}>Filters</ThemedText>
        <Pressable onPress={() => {/* reset logic */}}>
          <ThemedText style={styles.resetText}>Clear</ThemedText>
        </Pressable>
      </View>

      <ScrollView showsVerticalScrollIndicator={false} contentContainerStyle={styles.scrollPadding}>
        <View style={styles.content}>

          {/* AGE RANGE */}
          <View style={styles.section}>
            <ThemedText style={styles.ultraBoldLabel}>Age Range</ThemedText>
            <ThemedText style={styles.displayValue}>{minAge} — {maxAge}</ThemedText>
            <View style={styles.sliderBox}>
              <Slider 
                style={styles.slider} 
                minimumValue={18} maximumValue={80} step={1}
                value={minAge} onValueChange={setMinAge}
                minimumTrackTintColor={ACCENT_COLOR} thumbTintColor={ACCENT_COLOR}
              />
              <Slider 
                style={styles.slider} 
                minimumValue={18} maximumValue={100} step={1}
                value={maxAge} onValueChange={setMaxAge}
                minimumTrackTintColor={ACCENT_COLOR} thumbTintColor={ACCENT_COLOR}
              />
            </View>
          </View>

          {/* DISTANCE */}
          <View style={styles.section}>
            <ThemedText style={styles.ultraBoldLabel}>Maximum Distance</ThemedText>
            <ThemedText style={styles.displayValue}>{distance} km</ThemedText>
            <Slider 
              style={styles.slider} 
              minimumValue={1} maximumValue={200} step={1}
              value={distance} onValueChange={setDistance}
              minimumTrackTintColor={ACCENT_COLOR} thumbTintColor={ACCENT_COLOR}
            />
          </View>

          {/* LOOKING FOR */}
          <View style={styles.section}>
            <ThemedText style={styles.ultraBoldLabel}>Looking For</ThemedText>
            <View style={styles.pillContainer}>
              {['relationship', 'friendship', 'casual', 'networking'].map(val => (
                <Pressable 
                  key={val} 
                  style={[styles.pill, lookingFor === val && styles.activePill]}
                  onPress={() => { setLookingFor(val); Haptics.selectionAsync(); }}
                >
                  <ThemedText style={[styles.pillText, lookingFor === val && styles.activePillText]}>
                    {val.charAt(0).toUpperCase() + val.slice(1)}
                  </ThemedText>
                </Pressable>
              ))}
            </View>
          </View>

          {/* RELIGION */}
          <View style={styles.section}>
            <ThemedText style={styles.ultraBoldLabel}>Religion</ThemedText>
            <ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={styles.horizontalGap}>
              {['any', 'christian', 'muslim', 'spiritual', 'atheist'].map(val => (
                <Pressable 
                  key={val} 
                  style={[styles.pill, religion === val && styles.activePill]}
                  onPress={() => { setReligion(val); Haptics.selectionAsync(); }}
                >
                  <ThemedText style={[styles.pillText, religion === val && styles.activePillText]}>
                    {val.charAt(0).toUpperCase() + val.slice(1)}
                  </ThemedText>
                </Pressable>
              ))}
            </ScrollView>
          </View>
        </View>
      </ScrollView>

      {/* FIXED FOOTER BUTTON (SAFE ON ANDROID) */}
      <View style={[styles.footer, { backgroundColor: theme.background }]}>
        <Pressable 
          style={[styles.mainButton, saving && { opacity: 0.7 }]} 
          onPress={handleApply}
          disabled={saving}
        >
          <ThemedText style={styles.mainButtonText}>
            {saving ? 'UPDATING...' : 'SHOW PEOPLE'}
          </ThemedText>
        </Pressable>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  header: {
    flexDirection: "row",
    alignItems: "center",
    justifyContent: "space-between",
    paddingHorizontal: 20,
    paddingTop: Platform.OS === 'ios' ? 60 : 20,
    paddingBottom: 15,
  },
  headerTitle: { fontSize: 18, fontWeight: "800" },
  backCircle: {
    width: 40, height: 40, borderRadius: 20,
    backgroundColor: 'rgba(0,0,0,0.05)',
    alignItems: "center", justifyContent: "center",
  },
  resetText: { color: ACCENT_COLOR, fontWeight: "700", fontSize: 16 },
  scrollPadding: { paddingBottom: 120 }, // Enough space so button doesn't hide content
  content: { padding: 20 },
  section: { marginBottom: 35 },
  ultraBoldLabel: {
    fontSize: 24,
    fontWeight: "900",
    color: "#121212",
    marginBottom: 4,
    letterSpacing: -0.5,
  },
  displayValue: {
    fontSize: 18,
    fontWeight: "700",
    color: ACCENT_COLOR,
    marginBottom: 12,
  },
  sliderBox: { marginTop: 5 },
  slider: { width: '100%', height: 40 },
  pillContainer: { flexDirection: 'row', flexWrap: 'wrap', gap: 10, marginTop: 10 },
  horizontalGap: { gap: 10, paddingRight: 20 },
  pill: {
    paddingHorizontal: 22,
    paddingVertical: 12,
    borderRadius: 30,
    borderWidth: 2,
    borderColor: "#F0F0F0",
    backgroundColor: "#F9F9F9",
  },
  activePill: {
    borderColor: ACCENT_COLOR,
    backgroundColor: ACCENT_COLOR,
  },
  pillText: { fontSize: 15, fontWeight: "600", color: "#666" },
  activePillText: { color: "#FFF" },
  footer: {
    position: 'absolute',
    bottom: 0,
    width: '100%',
    paddingHorizontal: 20,
    paddingTop: 15,
    paddingBottom: Platform.OS === 'ios' ? 35 : 25, // Added extra padding for Android buttons
    borderTopWidth: 1,
    borderTopColor: 'rgba(0,0,0,0.05)',
  },
  mainButton: {
    height: 60,
    borderRadius: 30,
    backgroundColor: ACCENT_COLOR,
    alignItems: "center",
    justifyContent: "center",
    shadowColor: ACCENT_COLOR,
    shadowOffset: { width: 0, height: 10 },
    shadowOpacity: 0.3,
    shadowRadius: 20,
    elevation: 8,
  },
  mainButtonText: {
    color: "#FFF",
    fontSize: 18,
    fontWeight: "900",
    letterSpacing: 1,
  },
});
